from collections import deque
class Solution:
    def lexicographicallySmallestString(self, s):
        def cons(a, b):
            d = abs(ord(a) - ord(b))
            return d == 1 or d == 25
        seen = {s}
        best = s
        dq = deque([s])
        while dq:
            cur = dq.popleft()
            if cur < best:
                best = cur
            for i in range(len(cur) - 1):
                if cons(cur[i], cur[i + 1]):
                    nxt = cur[:i] + cur[i + 2:]
                    if nxt not in seen:
                        seen.add(nxt)
                        dq.append(nxt)
        return best

