import sys
from functools import lru_cache
class Solution:
    def lexicographicallySmallestString(self, s):
        sys.setrecursionlimit(10000)
        n = len(s)
        def cons(a, b):
            d = abs(ord(a) - ord(b))
            return d == 1 or d == 25
        gone = [[False] * n for _ in range(n)]
        for length in range(2, n + 1, 2):
            for i in range(0, n - length + 1):
                j = i + length - 1
                for k in range(i + 1, j + 1, 2):
                    inside = (k - 1 < i + 1) or gone[i + 1][k - 1]
                    rest = (j < k + 1) or gone[k + 1][j]
                    if cons(s[i], s[k]) and inside and rest:
                        gone[i][j] = True
                        break
        @lru_cache(maxsize=None)
        def best(i):
            if i == n:
                return ''
            res = s[i] + best(i + 1)
            for j in range(i + 1, n):
                if (j - i + 1) % 2 == 0 and gone[i][j]:
                    cand = best(j + 1)
                    if cand < res:
                        res = cand
            return res
        return best(0)

