var lexicographicallySmallestString = function(s) {
    const n = s.length;
    const cons = (a, b) => {
        const d = Math.abs(a.charCodeAt(0) - b.charCodeAt(0));
        return d === 1 || d === 25;
    };
    const gone = Array.from({length: n}, () => new Array(n).fill(false));
    for (let length = 2; length <= n; length += 2) {
        for (let i = 0; i + length - 1 < n; i++) {
            const j = i + length - 1;
            for (let k = i + 1; k <= j; k += 2) {
                const inside = (k - 1 < i + 1) || gone[i + 1][k - 1];
                const rest = (j < k + 1) || gone[k + 1][j];
                if (cons(s[i], s[k]) && inside && rest) { gone[i][j] = true; break; }
            }
        }
    }
    const memo = new Array(n + 1).fill(null);
    const best = (i) => {
        if (i === n) return '';
        if (memo[i] !== null) return memo[i];
        let res = s[i] + best(i + 1);
        for (let j = i + 1; j < n; j++) {
            if ((j - i + 1) % 2 === 0 && gone[i][j]) {
                const cand = best(j + 1);
                if (cand < res) res = cand;
            }
        }
        memo[i] = res;
        return res;
    };
    return best(0);
};
